  ('aboriginal-6f0ba476-moex-00735', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '在完全競爭市場內，每家廠商皆面臨一條_______的需求曲線：', '["完全無彈性（perfectlyinelastic）", "正斜率", "完全彈性（perfectlyelastic）", "負斜率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00736', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '假設廠商A及廠商B可採用的策略為：低價（L）及高價（H）。兩廠商採用此兩種策略所能得到 的報酬（單位為萬元）如下表： B L H L 100,90 200,80 A H 90,120 200,200 請問有幾個純粹策略（purestrategy）的Nash均衡解？', '["1個", "2個", "3個", "4個"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
