  ('aboriginal-6f0ba476-moex-00738', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '已開發的先進國家（包含我國），通常其消費占GNP之比率應是多少？而我國近年服務業約占實 質國民總產出之比例，又大約在何種水準？', '["21%-40%；50%", "41%-60%；60%", "61%-80%；70%", "81%-90%；80%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
